// Normalize funding rates to standard schema
// Symbols to watch and primary exchanges
const SYMBOLS_WATCH = ['BTC', 'ETH', 'SOL', 'XRP', 'DOGE', 'AVAX', 'MATIC', 'LINK'];
const EXCHANGES_PRIMARY = ['binance', 'bybit', 'okx', 'hyperliquid'];

const rawData = $input.first().json;
const fundingRates = rawData.funding_rates || rawData;
const timestamp = new Date().toISOString();

const normalized = [];

for (const symbol of SYMBOLS_WATCH) {
  const rates = {};
  let totalRate = 0;
  let exchangeCount = 0;
  let minRate = Infinity;
  let maxRate = -Infinity;

  for (const exchange of EXCHANGES_PRIMARY) {
    const raw = fundingRates?.[exchange]?.[symbol];
    if (raw !== undefined && raw !== null) {
      const pct = raw / 10000;
      const annualized = pct * 3 * 365; // Funding typically every 8h
      rates[exchange] = {
        raw,
        pct,
        annualized
      };
      totalRate += pct;
      exchangeCount++;
      if (pct < minRate) minRate = pct;
      if (pct > maxRate) maxRate = pct;
    }
  }

  if (exchangeCount > 0) {
    const avgRatePrimary = totalRate / exchangeCount;
    const maxSpread = maxRate - minRate;

    // Determine consensus
    let consensus = 'MIXED';
    if (avgRatePrimary > 0.001) {
      consensus = 'POSITIVE';
    } else if (avgRatePrimary < -0.001) {
      consensus = 'NEGATIVE';
    }

    normalized.push({
      symbol,
      source: 'loris',
      delay_minutes: 1,
      timestamp,
      rates,
      avg_rate_primary: avgRatePrimary,
      max_spread: maxSpread,
      consensus,
      oi_rank: SYMBOLS_WATCH.indexOf(symbol) + 1
    });
  }
}

return { json: { symbols: normalized, timestamp, source: 'loris' } };

// Detect funding rate signals
const normalizedData = $input.first().json;
const symbols = normalizedData.symbols || [];
const timestamp = normalizedData.timestamp;

const signals = [];
const alerts = [];

// Thresholds
const HIGH_FUNDING_POSITIVE = 0.0005; // 0.05%
const EXTREME_NEGATIVE = -0.0003; // -0.03%
const DIVERGENCE_THRESHOLD = 0.0008; // 0.08%

for (const item of symbols) {
  const { symbol, avg_rate_primary, max_spread, rates, consensus } = item;

  // Signal: ALTA FUNDING POSITIVO
  if (avg_rate_primary > HIGH_FUNDING_POSITIVE) {
    const signal = {
      type: 'HIGH_POSITIVE_FUNDING',
      symbol,
      severity: avg_rate_primary > 0.001 ? 'HIGH' : 'MEDIUM',
      message: `Funding positivo elevado: ${(avg_rate_primary * 100).toFixed(3)}% (anualizado ${(avg_rate_primary * 3 * 365 * 100).toFixed(1)}%)`,
      interpretation: 'Muchos longs pagando shorts — mercado sobrecalentado long',
      rates
    };
    signals.push(signal);
    if (signal.severity === 'HIGH') {
      alerts.push({ symbol, type: 'HIGH_POSITIVE_FUNDING', urgency: 'alta', data: signal });
    }
  }

  // Signal: FUNDING NEGATIVO EXTREMO
  if (avg_rate_primary < EXTREME_NEGATIVE) {
    const signal = {
      type: 'EXTREME_NEGATIVE_FUNDING',
      symbol,
      severity: 'HIGH',
      message: `Funding negativo extremo: ${(avg_rate_primary * 100).toFixed(3)}%`,
      interpretation: 'Shorts pagando longs — presión short extrema',
      rates
    };
    signals.push(signal);
    alerts.push({ symbol, type: 'EXTREME_NEGATIVE_FUNDING', urgency: 'alta', data: signal });
  }

  // Signal: DIVERGENCIA entre exchanges
  if (max_spread > DIVERGENCE_THRESHOLD) {
    const signal = {
      type: 'FUNDING_DIVERGENCE',
      symbol,
      severity: 'MEDIUM',
      message: `Divergencia: spread ${(max_spread * 100).toFixed(3)}% entre exchanges`,
      interpretation: 'Desacuerdo entre exchanges sobre valoración del riesgo',
      rates
    };
    signals.push(signal);
  }
}

// Global reading
const positiveCount = symbols.filter(s => s.avg_rate_primary > HIGH_FUNDING_POSITIVE).length;
const negativeCount = symbols.filter(s => s.avg_rate_primary < EXTREME_NEGATIVE).length;

let globalReading = 'NEUTRAL';
if (positiveCount >= 3) globalReading = 'OVERHEATED';
else if (negativeCount >= 2) globalReading = 'UNDERHEATED';
else if (positiveCount > negativeCount) globalReading = 'BULLISH_SKEW';
else if (negativeCount > positiveCount) globalReading = 'BEARISH_SKEW';

return {
  json: {
    signals,
    alerts,
    global_reading: globalReading,
    summary: {
      positive_count: positiveCount,
      negative_count: negativeCount,
      total_symbols: symbols.length
    },
    symbols,
    timestamp
  }
};

// Format human-readable summary
const signalData = $input.first().json;
const symbols = signalData.symbols || [];
const signals = signalData.signals || [];
const globalReading = signalData.global_reading || 'NEUTRAL';
const timestamp = new Date();

const fecha = timestamp.toISOString().split('T')[0];
const hora = timestamp.toTimeString().split(' ')[0];

let summary = `FUNDING RATES — ${fecha} ${hora}\n`;
summary += `Fuente: Loris Tools (25+ exchanges)\n`;
summary += `RESUMEN POR ACTIVO:\n`;

for (const item of symbols) {
  const { symbol, rates, consensus, avg_rate_primary } = item;
  const rateStrings = [];
  for (const [exchange, data] of Object.entries(rates)) {
    rateStrings.push(`${exchange.charAt(0).toUpperCase() + exchange.slice(1)} ${(data.pct * 100).toFixed(2)}%`);
  }
  const rateStr = rateStrings.join(' | ');
  summary += `${symbol}: ${rateStr} → Sesgo: ${consensus}\n`;
}

if (signals.length > 0) {
  summary += `\nSEÑALES DETECTADAS:\n`;
  for (const signal of signals) {
    if (signal.severity === 'HIGH') {
      summary += `⚠️ ${signal.symbol}: ${signal.message} — ${signal.interpretation}\n`;
    }
  }
}

summary += `\nLECTURA GLOBAL:\n`;
summary += `Funding ${globalReading.toLowerCase()} en ${symbols.filter(s => s.consensus === 'POSITIVE').length} activos → mercado en modo ${globalReading}\n`;

return {
  json: {
    summary,
    global_reading: globalReading,
    signals,
    symbols,
    timestamp: signalData.timestamp
  }
};
